# Adaptive Rejection Sampling (ARS) Implementation

#' Check if the inputs to the ARS function are valid
#' @param n Number of samples
#' @param S Initial set of points
#' @param domain Support of the distribution
validate_inputs <- function(n, S, domain) {
  if (n <= 0 || n %% 1 != 0) stop("n must be a positive integer")
  if (length(domain) != 2 || domain[1] >= domain[2]) stop("Invalid domain")

  S <- sort(unique(S))
  S <- S[S > domain[1] & S < domain[2]]

  if (length(S) < 1) stop("Initial points S must be within the domain")

  return(S)
}

#' Compute log density and its derivative
#' @param x_vals Points to evaluate
#' @param f Density function
#' @param domain Support of the distribution
compute_h_hprime <- function(x_vals, f, domain) {
  h <- log(f(x_vals))

  if (any(is.infinite(h) | is.na(h))) {
    stop("Density function evaluates to 0 or NA at some initial points.")
  }

  eps <- 1e-5

  # Calculate derivative numerically, respecting domain boundaries
  step_plus <- pmin(x_vals + eps, domain[2]) - x_vals
  step_minus <- x_vals - pmax(x_vals - eps, domain[1])

  h_plus <- log(f(x_vals + step_plus))
  h_minus <- log(f(x_vals - step_minus))

  h_prime <- (h_plus - h_minus) / (step_plus + step_minus)

  list(x = x_vals, h = h, hp = h_prime)
}

#' Adaptive Rejection Sampler
#' @param n Number of samples
#' @param f Function calculating the unnormalized density
#' @param S Initial set of points
#' @param domain Support of the distribution
#' @return A numeric vector of length n containing the samples
ars <- function(n, f, S = c(-2, 2), domain = c(-Inf, Inf)) {
  S <- validate_inputs(n, S, domain)

  samples <- numeric(n)
  count <- 0

  while(count < n) {
    pts <- compute_h_hprime(S, f, domain)
    k <- length(pts$x)

    # Check log-concavity
    if (k > 1) {
      hp_diff <- diff(pts$hp)
      if (any(hp_diff > 1e-5)) {
        stop("non-log-concave density: derivative of log-density is increasing.")
      }

      # Filter points with nearly parallel tangents to avoid instability
      keep <- c(TRUE, hp_diff < -1e-6)
      pts$x <- pts$x[keep]
      pts$h <- pts$h[keep]
      pts$hp <- pts$hp[keep]
      k <- length(pts$x)
    }

    # Check if bounds are valid
    if (pts$hp[1] <= 0 && domain[1] == -Inf) {
      # Add a point to the left
      S <- c(pts$x[1] - 1, S)
      next
    }
    if (pts$hp[k] >= 0 && domain[2] == Inf) {
      # Add a point to the right
      S <- c(S, pts$x[k] + 1)
      next
    }

    # Calculate intersections z
    z <- numeric(k + 1)
    z[1] <- domain[1]
    z[k + 1] <- domain[2]

    if (k > 1) {
      for (i in 1:(k - 1)) {
        num <- pts$h[i+1] - pts$h[i] - pts$x[i+1] * pts$hp[i+1] + pts$x[i] * pts$hp[i]
        den <- pts$hp[i] - pts$hp[i+1]
        z[i+1] <- num / den
      }
    }

    # Calculate probabilities (weights)
    u_max <- max(pts$h)
    w <- numeric(k)
    for (i in 1:k) {
      u_left <- pts$h[i] + pts$hp[i] * (z[i] - pts$x[i])
      u_right <- pts$h[i] + pts$hp[i] * (z[i+1] - pts$x[i])

      if (abs(pts$hp[i]) < 1e-8) {
        w[i] <- (z[i+1] - z[i]) * exp(u_left - u_max)
      } else if (pts$hp[i] > 0) {
        w[i] <- exp(u_right - u_max) * (-expm1(-pts$hp[i] * (z[i+1] - z[i]))) / pts$hp[i]
      } else {
        w[i] <- exp(u_left - u_max) * expm1(pts$hp[i] * (z[i+1] - z[i])) / pts$hp[i]
      }
    }

    p <- w / sum(w)

    # Sample an interval
    idx <- sample(1:k, size = 1, prob = p)

    # Sample x from the interval
    U <- runif(1)
    if (abs(pts$hp[idx]) < 1e-8) {
      x_star <- z[idx] + U * (z[idx+1] - z[idx])
    } else if (pts$hp[idx] > 0) {
      x_star <- z[idx+1] + (1 / pts$hp[idx]) * log(U + (1 - U) * exp(-pts$hp[idx] * (z[idx+1] - z[idx])))
    } else {
      x_star <- z[idx] + (1 / pts$hp[idx]) * log(1 - U + U * exp(pts$hp[idx] * (z[idx+1] - z[idx])))
    }

    # Evaluate envelopes
    u_x <- pts$h[idx] + pts$hp[idx] * (x_star - pts$x[idx])

    l_x <- -Inf
    if (k > 1 && x_star >= pts$x[1] && x_star <= pts$x[k]) {
      # Find j such that x_star is in [x_j, x_{j+1}]
      j <- max(which(pts$x <= x_star))
      if (j == k) j <- k - 1 # Edge case if x_star exactly equals pts$x[k]
      l_x <- pts$h[j] + (pts$h[j+1] - pts$h[j]) / (pts$x[j+1] - pts$x[j]) * (x_star - pts$x[j])
    }

    W <- runif(1)

    if (log(W) <= l_x - u_x) {
      count <- count + 1
      samples[count] <- x_star
    } else {
      h_x <- log(f(x_star))
      if (log(W) <= h_x - u_x) {
        count <- count + 1
        samples[count] <- x_star
      }
      # Update S with new point
      S <- sort(unique(c(S, x_star)))
    }
  }

  return(samples)
}

#' Formal testing function
test <- function() {
  cat("Running formal tests for ARS...\n")

  # Test 1: Standard Normal
  cat("\nTEST 1: Standard Normal Distribution\n")
  f_norm <- function(x) dnorm(x)
  tryCatch({
    n_samples <- 5000
    samples_norm <- ars(n_samples, f_norm, S = c(-2, 0, 2), domain = c(-Inf, Inf))
    m <- mean(samples_norm)
    s <- sd(samples_norm)

    cat(sprintf("Generated %d samples. Mean: %.4f, SD: %.4f\n", n_samples, m, s))

    if (abs(m) < 0.1 && abs(s - 1) < 0.1) {
      cat("TEST_NORMAL: PASS\n")
      write.table(samples_norm, "/app/normal_samples.txt", row.names = FALSE, col.names = FALSE)
      cat("Saved samples to /app/normal_samples.txt\n")
    } else {
      cat("TEST_NORMAL: FAIL\n")
    }
  }, error = function(e) {
    cat("TEST_NORMAL: FAIL - Error: ", e$message, "\n")
  })

  # Test 2: Exponential Distribution
  cat("\nTEST 2: Exponential Distribution (rate = 1)\n")
  f_exp <- function(x) dexp(x)
  tryCatch({
    n_samples <- 5000
    samples_exp <- ars(n_samples, f_exp, S = c(1, 2), domain = c(0, Inf))
    m <- mean(samples_exp)
    s <- sd(samples_exp)

    cat(sprintf("Generated %d samples. Mean: %.4f, SD: %.4f\n", n_samples, m, s))

    if (abs(m - 1) < 0.1 && abs(s - 1) < 0.1) {
      cat("TEST_EXPONENTIAL: PASS\n")
      write.table(samples_exp, "/app/exponential_samples.txt", row.names = FALSE, col.names = FALSE)
      cat("Saved samples to /app/exponential_samples.txt\n")
    } else {
      cat("TEST_EXPONENTIAL: FAIL\n")
    }
  }, error = function(e) {
    cat("TEST_EXPONENTIAL: FAIL - Error: ", e$message, "\n")
  })

  # Test 3: Non-log-concave distribution (Student's t with df=2)
  cat("\nTEST 3: Non-log-concave Distribution (Student's t, df=2)\n")
  f_t <- function(x) dt(x, df = 2)
  tryCatch({
    samples_t <- ars(100, f_t, S = c(-1, 0, 1), domain = c(-Inf, Inf))
    cat("TEST_NON_LOG_CONCAVE: FAIL - Did not catch non-log-concavity\n")
  }, error = function(e) {
    if (grepl("non-log-concave", e$message)) {
      cat(sprintf("Caught expected error: %s\n", e$message))
      cat("TEST_NON_LOG_CONCAVE: PASS\n")
    } else {
      cat("TEST_NON_LOG_CONCAVE: FAIL - Unexpected error: ", e$message, "\n")
    }
  })

  # Test 4: Invalid inputs
  cat("\nTEST 4: Invalid inputs\n")
  tryCatch({
    ars(-10, f_norm)
    cat("TEST_INVALID_INPUTS: FAIL - Did not catch negative n\n")
