      cat("TEST_INVALID_INPUTS: PASS\n")
    } else {
      cat("TEST_INVALID_INPUTS: FAIL - Unexpected error: ", e$message, "\n")
    }
  })
}

# Run tests if executed as script
if (sys.nframe() == 0) {
  test()
}
